329 /// If this constant is a constant offset from a global, return the global and
330 /// the constant. Because of constantexprs, this function is recursive.
331 bool llvm::IsConstantOffsetFromGlobal(Constant *C, GlobalValue *&GV,
332                                       APInt &Offset, const DataLayout &DL,
333                                       DSOLocalEquivalent **DSOEquiv) {
334   if (DSOEquiv)
335     *DSOEquiv = nullptr;
336 
337   // Trivial case, constant is the global.
338   if ((GV = dyn_cast<GlobalValue>(C))) {
339     unsigned BitWidth = DL.getIndexTypeSizeInBits(GV->getType());
340     Offset = APInt(BitWidth, 0);
341     return true;
342   }
343 
344   if (auto *FoundDSOEquiv = dyn_cast<DSOLocalEquivalent>(C)) {
345     if (DSOEquiv)
346       *DSOEquiv = FoundDSOEquiv;
347     GV = FoundDSOEquiv->getGlobalValue();
348     unsigned BitWidth = DL.getIndexTypeSizeInBits(GV->getType());
349     Offset = APInt(BitWidth, 0);
350     return true;
351   }
352 
353   // Otherwise, if this isn't a constant expr, bail out.
354   auto *CE = dyn_cast<ConstantExpr>(C);
355   if (!CE) return false;
356 
357   // Look through ptr->int and ptr->ptr casts.
358   if (CE->getOpcode() == Instruction::PtrToInt ||
359       CE->getOpcode() == Instruction::PtrToAddr ||
360       CE->getOpcode() == Instruction::BitCast)
361     return IsConstantOffsetFromGlobal(CE->getOperand(0), GV, Offset, DL,
362                                       DSOEquiv);
363 
364   // i32* getelementptr ([5 x i32]* @a, i32 0, i32 5)
365   auto *GEP = dyn_cast<GEPOperator>(CE);
366   if (!GEP)
367     return false;
368 
369   unsigned BitWidth = DL.getIndexTypeSizeInBits(GEP->getType());
370   APInt TmpOffset(BitWidth, 0);
371 
372   // If the base isn't a global+constant, we aren't either.
373   if (!IsConstantOffsetFromGlobal(CE->getOperand(0), GV, TmpOffset, DL,
374                                   DSOEquiv))
375     return false;
376 
377   // Otherwise, add any offset that our operands provide.
378   if (!GEP->accumulateConstantOffset(DL, TmpOffset))
379     return false;
380 
381   Offset = TmpOffset;
382   return true;
383 }
